mapper.select:
SELECT id, record_date AS recordDate, commodity_code AS commodityCode, total_open_interest AS totalOpenInterest, fund_long AS fundLong, fund_short AS fundShort, fund_net AS fundNet, commercial_long AS commercialLong, commercial_short AS commercialShort, reportable_traders AS reportableTraders, record_time AS recordTime FROM cftc_cot
commodity_code = #{commodityCode}
ORDER BY record_date DESC LIMIT #{offset}, #{size}
